import{_ as a,o as p,c as t,j as r,a as b,a1 as n}from"./chunks/framework.Bp7r_-XI.js";const h=JSON.parse('{"title":"支援战甲-协奏曲","description":"","frontmatter":{},"headers":[],"relativePath":"4.资源分区/7.物品与装备/7.载具及随从/载具/3.B级/支援战甲-协奏曲.md","filePath":"4.资源分区/7.物品与装备/7.载具及随从/载具/3.B级/支援战甲-协奏曲.md"}'),s={name:"4.资源分区/7.物品与装备/7.载具及随从/载具/3.B级/支援战甲-协奏曲.md"};function o(d,e,_,l,i,c){return p(),t("div",null,[...e[0]||(e[0]=[r("h1",{id:"支援战甲-协奏曲",tabindex:"-1"},[b("支援战甲-协奏曲 "),r("a",{class:"header-anchor",href:"#支援战甲-协奏曲","aria-label":'Permalink to "支援战甲-协奏曲"'},"​")],-1),r("table",{class:"bannerparthead"},[r("tbody",null,[r("tr",{id:"hdr"},[r("td",{class:"runninghead",nowrap:""},"TMD：新世短歌034")])])],-1),n('<h1 id="支援战甲-协奏曲-1" tabindex="-1">支援战甲-协奏曲 <a class="header-anchor" href="#支援战甲-协奏曲-1" aria-label="Permalink to &quot;支援战甲-协奏曲&quot;">​</a></h1><p>支援战甲-协奏曲<br> 推荐属性：耐力或力量属性之一不低于14<br> 价格：B+2000<br> 介绍：“真理只在大炮射程之内”这一上上个前年的朴素真理，即使放在现在的浩瀚星宇之中也不过时。秉承着这一真理设计并制造的战甲在最初饱受诟病，无论是对其抗击打能力的担忧，平台载力的不看好，以及续航能力的解决问题。可要是换个说法——事实上我们是在为我们前线的每个士兵装备更高效的作战单元，并且更为廉价且易于生产？而非用传统的精锐单位作为对焚风战甲的评判标准，那很多问题其实也不是问题了。<br> 相比与其他战甲，协奏曲被称之为“战甲”实际上有些牵强。不但其的保护面积与破天强袭难分伯仲，而且相比对方有更多的弱点部位，但介于其火力手的定位，实际这点对其影响并非严重。更需要担心的其实是驾驶员的耳膜安全，内脏健康之类的——长期与重火力近距离打交道，对身体的无形损害可不小。<br> 【机密档案：地球联邦曾考虑过给予重刑犯改造机会，但考虑战场上的严重不可控性与议会的人道主义指控，遂在官方层面搁置】</p><p>类型：轻型载具<br> 体积：12<br> 结构值：52<br> 防御面：15<br> 移动速度/轮：基础200m 加速度100m 最大速度400m<br> 载员：1名体积不大于5的驾驶员</p><p>【枪炮三稳系统】：无论战报多么的华丽，战场上的残酷对于士兵而言是客观的事实，而我们能做些什么？自然是架起最厚重与密集的火力，用硝烟与火药为队友创造一片安全地带！无需担心弹药的损耗，人命可贵，而弹药廉价——正所谓优势火力学说。协奏曲的下属武器攻击均可以结合在一次移动当中。</p><p>【弹道火控系统】：同时操作手中的武器和协奏曲自带的火力单位并非易事，尤其是协奏曲们相较于正经火炮而言短小得多的炮击距离，因而在必要时，将开火的权限交由机甲全新构建的AI很有必要，但我们仍旧为有需要的驾驶员保留亲手操作的权限。<br> 每轮一次，以自由动作宣言，令协奏曲的内置AI接管某件下属武器，令其视为拥有【预设】特性，持续一轮。</p><p>【集成远火一体】：相对于原本使用的炮镜，协奏曲选择配备装备在面部的瞄准面板，使用全息瞄准镜原理展现标尺与准星。其配备的高像素摄像头可以放大远处人眼难以捕捉到的细小目标，并且可以接入火控系统，快速计算所需的仰角随后射击，也可接入内置AI自动检索视距内能够辨析的移动目标，并汇报给驾驶员。这视为一种敏感范围翻倍的能力。</p><p>——【下属武器】——<br> 每把武器都是独一无二的，暂不支持重复购买安装同件武器<br> 目前提供的武器安装部位有——肩部（左右各一位置），手臂（左右各一位置），背部。</p><p>捍卫者120mm滑膛炮<br> 价格：B+3000<br> 介绍：来自捍卫者坦克搭载火炮的改装版本，相信火星工程部的人员们，他们真的在减轻武器重量上竭尽全力了。另外在最新的火控系统与计算系统，以及近炸弹药的帮助下，这门火炮不仅在对付单个敌人事卓有成效，并且对于那些试图挑衅我方的敌方空军，它也能给予回击。</p><p>武器伤害：18L<br> 武器特性：【高速15】【破甲10】【贯穿】<br> 伤害类型：物理-穿刺<br> 射程：600m<br> 装弹量：1</p><p>【选票的支持！】：你的身后是千万灯火人家，你的前方是前赴后继的战友们，不要退缩！屹立于此，向一切来犯之敌宣泄我们的愤怒，让每一个小伙子都能回家，放入属于他们的选票！但要记住，战场上你不是一个人在战斗，在你身后的是整个联邦！还有纳税人们的支持，例如他们为之付款的【纳税人弹药机】，能够在战场为你提供所需的弹药，这视为拥有【无限子弹】特性</p><p>【以民主之拳！】：切记，对没有意图成为俘虏的敌人没有人道主义可言！对待这种蛮夷，就要以民主的铁拳为之重击！而那些敢于对我们反击的敌人，就显然不愿意成为俘虏。以本武器进行的攻击检定具有【加骰等级上升一级（至多为8加骰）】，并且效果线由直线型变为抛物线型（这意味着绕过一些掩体和建筑对目标攻顶打击是可行的）</p><p>鞭挞者20mm机炮<br> 价格：B+2000<br> 介绍：为地球联邦大部分载具装载的制式重火力装备，其简易可靠的三管结构保证了战场上对于敌人的火力压制的同时，还确保了纳税人花的每分钱都能被高效的作用在敌人身上。这也是为数不多从地球联邦之前的时代继承的武器装备了。特殊的，本武器为成对安装，因而不支持在背部安装。</p><p>武器伤害：15L<br> 武器特性：【高速10】【破甲5】【连射】【贯穿】<br> 伤害类型：物理-穿刺<br> 射程：150m<br> 装弹量：100</p><p>【选票的支持！】：你的身后是千万灯火人家，你的前方是前赴后继的战友们，不要退缩！屹立于此，向一切来犯之敌宣泄我们的愤怒，让每一个小伙子都能回家，放入属于他们的选票！但要记住，战场上你不是一个人在战斗，在你身后的是整个联邦！还有纳税人们的支持，例如他们为之付款的【纳税人弹药机】，能够在战场为你提供所需的弹药，这视为拥有【无限子弹】特性</p><p>【以民主之声！】：切记，对那些没有智慧的原始敌人没有法律道德可言！对待这种未开化民，就要播报民主之声让它们畏惧！不要怀有仁慈，士兵。你的任何一个迟疑都可能导致你的战友被那些嗜血种族撕碎。以本武器进行的攻击检定具有【加骰等级上升一级（至多为8加骰）】，并且可以令某次攻击的射程提升150米，转为对前方锥形所有目标进行不分敌我的射击。<br> （TIP：请不要担忧你的队友，地球联邦的医疗技术全银河系第一！）</p><p>【双倍部件，双倍火力！】每轮一次，使用该武器进行的攻击检定可以重新投掷一次，两次结果取高。</p><p>解放者高能光束<br> 价格：B+2000<br> 介绍：从诞生之初就饱受争议的能量武器，虽然相比实弹武器有诸多便利之处，但更高的故障率与苛刻的维护成本还是先制了其的缩小下放部署。但如今面对以智能机械为主的敌人，能量武器能够高效熔融金属的优势被得到重视，开始活跃在与【终焉执行者】对抗的前线。</p><p>武器伤害：18L<br> 武器特性：【高速16】【超级贯穿】【能量武器】<br> 伤害类型：物理-穿刺<br> 射程：300m<br> 装弹量：1</p><p>【选票的支持！】：你的身后是千万灯火人家，你的前方是前赴后继的战友们，不要退缩！屹立于此，向一切来犯之敌宣泄我们的愤怒，让每一个小伙子都能回家，放入属于他们的选票！但要记住，战场上你不是一个人在战斗，在你身后的是整个联邦！还有纳税人们的支持，例如他们为之付款的【纳税人反应堆】，能够在战场为你提供所需的能量，这视为拥有【无限子弹】特性</p><p>【以民主之光！】切记，对那些没有自由意志的敌人没有任何同情可谈！对待这些没有意志的爪牙，就要以民主照耀它们令之消亡！不要心存侥幸，士兵。不要忘记它们给我们带来的苦难，即使它们应当拥有辩解的权利，但也要等到战事结束，尘埃落定之时！以本武器进行的攻击检定具有【加骰等级上升一级（至多为8加骰）】。</p><hr><p>Copyright ? 2025 <a href="http://www.goddessfantasy.net/bbs/index.php?board=2008.0" target="_blank" rel="noreferrer">TMDtrpg制作组</a>. All Rights Reserved.</p>',22)])])}const f=a(s,[["render",o]]);export{h as __pageData,f as default};
